"use strict";parserFactory.register("readnovelmtl.com",()=>new ReadnovelmtlParser);class ReadnovelmtlParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector(".accordion");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("#content")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".card-body")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".mb-4 p")]}}